CREATE TABLE `comber_production_detail` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `header_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `machine_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `employee_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `prodn_mixing` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `act_hank` decimal(10,2) DEFAULT '0.00',
  `run_hrs` decimal(5,2) DEFAULT '0.00',
  `run_min` int DEFAULT '0',
  `waste` decimal(10,4),
  `act_prodn` decimal(10,2) DEFAULT '0.00',
  `waste_percent` decimal(10,4) DEFAULT '0.0000',
  `act_effi_percent` decimal(10,2) DEFAULT '0.00',
  `uti_percent` decimal(10,2) DEFAULT '0.00',
  `std_hrs` decimal(10,2) DEFAULT '0.00',
  `work_time` int DEFAULT '510',
  `session_no` int DEFAULT '1',
  `is_verified` tinyint(1) DEFAULT '0',
  `verified_at` datetime DEFAULT NULL,
  `is_locked` tinyint(1) DEFAULT '0',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `total_stoppage_mins` int DEFAULT '0',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
