DROP TABLE IF EXISTS `spinning_machines`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `spinning_machines` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `machine_no` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `sort_order` int DEFAULT '0',
  `description` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `make_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'LMW',
  `allocated_spindles` int NOT NULL DEFAULT '1104',
  `is_active` tinyint(1) DEFAULT '1',
  `remarks` text COLLATE utf8mb4_unicode_ci,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `frame_no` int DEFAULT NULL,
  `mc_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT '225',
  `model` text COLLATE utf8mb4_unicode_ci,
  `group_no` int DEFAULT '0',
  `installed_date` date DEFAULT '2015-04-01',
  `production_kgs_manual_entry` tinyint(1) DEFAULT '0',
  `direct_hank_entry` tinyint(1) DEFAULT '1',
  `activated_at` date DEFAULT NULL,
  `deactivated_at` date DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
