DROP TABLE IF EXISTS `spinning_production_detail`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `spinning_production_detail` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `header_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `machine_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `count_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `act_hank` decimal(10,2) DEFAULT NULL,
  `act_prodn` decimal(10,2) DEFAULT NULL,
  `waste` decimal(10,4) DEFAULT '0.1000',
  `waste_percent` decimal(5,2) DEFAULT NULL,
  `gps` decimal(10,2) DEFAULT NULL,
  `worked_spindles` decimal(10,2) DEFAULT NULL,
  `stopped_spindles` decimal(10,2) DEFAULT NULL,
  `exp_gps` decimal(10,2) DEFAULT NULL,
  `total_stoppage_mins` int DEFAULT '0',
  `session_no` int DEFAULT '1',
  `is_verified` tinyint(1) DEFAULT '0',
  `verified_at` datetime DEFAULT NULL,
  `is_locked` tinyint(1) DEFAULT '0',
  `remarks` text COLLATE utf8mb4_unicode_ci,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `sider1_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sider2_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `work_time` int DEFAULT '500',
  `run_time` int DEFAULT '510',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
